 1→package com.yottastudios.ns.collabspace.shared.config.initializers;
 2→
 3→import java.io.IOException;
 4→import lombok.extern.slf4j.Slf4j;
 5→import org.springframework.boot.env.YamlPropertySourceLoader;
 6→import org.springframework.context.ApplicationContextInitializer;
 7→import org.springframework.context.ConfigurableApplicationContext;
 8→import org.springframework.core.env.ConfigurableEnvironment;
 9→import org.springframework.core.env.PropertySource;
10→import org.springframework.core.io.ClassPathResource;
11→import org.springframework.core.io.Resource;
12→
13→/**
14→ * enterprise environment profile initializers.
15→ */
16→@Slf4j
17→public class EnterpriseEnvironmentInitializers
18→    implements ApplicationContextInitializer<ConfigurableApplicationContext> {
19→
20→    private final YamlPropertySourceLoader loader = new YamlPropertySourceLoader();
21→
22→    @Override
23→    public void initialize(ConfigurableApplicationContext applicationContext) {
24→        ConfigurableEnvironment environment = applicationContext.getEnvironment();
25→        Resource path = new ClassPathResource("enterprise/enterprise.yml");
26→        PropertySource<?> propertySource = loadYaml(path);
27→        if (propertySource != null) {
28→            environment.getPropertySources().addLast(propertySource);
29→        }
30→    }
31→
32→    private PropertySource<?> loadYaml(Resource path) {
33→        if (!path.exists()) {
34→            return null;
35→        }
36→        try {
37→            return this.loader.load("enterprise", path).get(0);
38→        } catch (IOException ex) {
39→            throw new IllegalStateException("Failed to load yaml configuration from " + path, ex);
40→        }
41→    }
42→}
