  6→
  7→import cn.hutool.core.util.ArrayUtil;
  8→import com.yottastudios.ns.collabspace.shared.config.security.CsrfBeforeFilter;
  9→import com.yottastudios.ns.collabspace.shared.util.IgnorePathHelper;
 10→import jakarta.annotation.Resource;
 11→import org.springframework.context.annotation.Bean;
 12→import org.springframework.context.annotation.Configuration;
 13→import org.springframework.core.annotation.Order;
 14→import org.springframework.security.config.annotation.web.builders.HttpSecurity;
 15→import org.springframework.security.config.annotation.web.configuration.EnableWebSecurity;
 16→import org.springframework.security.config.annotation.web.configurers.AbstractHttpConfigurer;
 17→import org.springframework.security.config.annotation.web.configurers.HeadersConfigurer;
 18→import org.springframework.security.crypto.bcrypt.BCryptPasswordEncoder;
 19→import org.springframework.security.crypto.password.PasswordEncoder;
 20→import org.springframework.security.web.SecurityFilterChain;
 21→import org.springframework.security.web.csrf.CookieCsrfTokenRepository;
 22→import org.springframework.security.web.csrf.CsrfFilter;
 23→import org.springframework.security.web.csrf.CsrfTokenRequestAttributeHandler;
 24→import org.springframework.security.web.util.matcher.AntPathRequestMatcher;
 25→import org.springframework.security.web.util.matcher.NegatedRequestMatcher;
 26→import org.springframework.security.web.util.matcher.OrRequestMatcher;
 27→import org.springframework.security.web.util.matcher.RequestMatcher;
 28→import org.springframework.session.FindByIndexNameSessionRepository;
 29→import org.springframework.session.Session;
 30→import org.springframework.session.security.SpringSessionBackedSessionRegistry;
 31→
 32→/**
 33→ * <p>
 34→ * spring Security config.
 35→ * </p>
 36→ *
 37→ * @author Shawn Deng
 38→ */
 39→@Configuration
 40→@EnableWebSecurity
 41→public class WebSecurityConfig<S extends Session> {
 42→
 43→    @Resource
 44→    private FindByIndexNameSessionRepository<S> sessionRepository;
 45→
 46→    @Bean
 47→    public PasswordEncoder passwordEncoder() {
 48→        return new BCryptPasswordEncoder();
 49→    }
 50→
 51→    @Bean
 52→    public SpringSessionBackedSessionRegistry<S> sessionRegistry() {
 53→        return new SpringSessionBackedSessionRegistry<>(this.sessionRepository);
 54→    }
 55→
 56→    /**
 57→     * configure security filter chain.
 58→     *
 59→     * @param http http security
 60→     * @return security filter chain
 61→     * @throws Exception exception
 62→     */
 63→    @Bean
 64→    @Order(2)
 65→    public SecurityFilterChain filterChain(HttpSecurity http) throws Exception {
 66→        RequestMatcher oauth2EndpointsMatcher = new OrRequestMatcher(
 67→            new AntPathRequestMatcher("/oauth2/**"),
 68→            new AntPathRequestMatcher("/.well-known/**"),
 69→            new AntPathRequestMatcher("/connect/**"),
 70→            new AntPathRequestMatcher("/userinfo")
 71→        );
 72→        http.securityMatcher(new NegatedRequestMatcher(oauth2EndpointsMatcher));
 73→        
 74→        CookieCsrfTokenRepository cookieCsrfTokenRepository = new CookieCsrfTokenRepository();
 75→        cookieCsrfTokenRepository.setCookieCustomizer((cookie) -> cookie.httpOnly(false));
 76→        cookieCsrfTokenRepository.setCookiePath("/");
 77→        // opt-out of deferred csrf tokens
 78→        CsrfTokenRequestAttributeHandler requestHandler = new CsrfTokenRequestAttributeHandler();
 79→        requestHandler.setCsrfRequestAttributeName(null);
 80→        http
 81→            .cors(withDefaults())
 82→            .sessionManagement((sessionManagement) -> sessionManagement
 83→                .sessionFixation().migrateSession()
 84→                .maximumSessions(5)
 85→                .sessionRegistry(sessionRegistry())
 86→            )
 87→            .authorizeHttpRequests((auth) -> auth.anyRequest().permitAll())
 88→            .httpBasic(AbstractHttpConfigurer::disable)
 89→            .formLogin(AbstractHttpConfigurer::disable)
 90→            .logout(AbstractHttpConfigurer::disable)
 91→            .headers(
 92→                (headers) -> headers.frameOptions(HeadersConfigurer.FrameOptionsConfig::disable))
 93→            .csrf((csrf) ->
 94→                csrf.csrfTokenRepository(cookieCsrfTokenRepository)
 95→                    .csrfTokenRequestHandler(requestHandler)
 96→                    .ignoringRequestMatchers(
 97→                        ArrayUtil.toArray(IgnorePathHelper.getInstant().iterator(), String.class)
 98→                    )
 99→                    .ignoringRequestMatchers(
100→                        "/internal/**",
101→                        "/actuator/**",
102→                        "/social/**",
103→                        "/wechat/**",
104→                        "/feishu/**",
105→                        "/lark/event/**",
106→                        "/lark/idp/**",
107→                        "/vcode/**",
108→                        "/dingtalk/**",
109→                        "/auth0/**",
110→                        "/idaas/**",
111→                        "/ai/**",
112→                        "/airagent/**",
113→                        "/appsumo/**",
114→                        "/invitation/**",
115→                        "/assets/**",
116→                        "/oauth2/**",
117→                        "/.well-known/**",
118→                        "/userinfo",
119→                        "/v3/api-docs/**",
120→                        "/nextcloud/**"
121→                    )
122→            )
123→            .addFilterBefore(new CsrfBeforeFilter(), CsrfFilter.class);
124→        return http.build();
125→    }
126→}
