138→    @Bean
139→    public Declarables nextcloudWebhookShardDeclarables() {
140→        DirectExchange exchange = new DirectExchange(NEXTCLOUD_WEBHOOK_DIRECT_EXCHANGE);
141→        List<Declarable> items = new ArrayList<>();
142→        for (int i = 0; i < NEXTCLOUD_WEBHOOK_SHARD_COUNT; i++) {
143→            Queue queue = QueueBuilder.durable(NEXTCLOUD_WEBHOOK_SHARD_QUEUE_PREFIX + i).build();
144→            String routingKey = NEXTCLOUD_WEBHOOK_SHARD_ROUTING_KEY_PREFIX + i;
145→            items.add(queue);
146→            items.add(BindingBuilder.bind(queue).to(exchange).with(routingKey));
147→        }
148→        return new Declarables(items);
149→    }
