151→    /**
152→     * Nextcloud 分片消费专用 ContainerFactory：
153→     * 使用批量回调 + AUTO ACK（监听方法成功返回后 ack，抛异常后 reject 且不 requeue）。
154→     * 通过 receiveTimeout 控制 2s 收包窗口，同 shard 单消费者保证顺序。
155→     */
156→    @Bean
157→    public SimpleRabbitListenerContainerFactory nextcloudShardBatchContainerFactory(ConnectionFactory connectionFactory,
158→                                                                                    NextcloudProperties nextcloudProperties) {
159→        NextcloudProperties.Callback callback = nextcloudProperties.getCallback();
160→        int batchMaxSize = Math.max(callback.getBatchMaxSize(), 1);
161→        long receiveTimeoutMs = Math.max(callback.getBatchReceiveTimeoutMs(), 1);
162→        int concurrency = Math.max(callback.getConsumerConcurrencyPerShard(), 1);
163→
164→        SimpleRabbitListenerContainerFactory factory = new SimpleRabbitListenerContainerFactory();
165→        factory.setConnectionFactory(connectionFactory);
166→        factory.setConcurrentConsumers(concurrency);
167→        factory.setMaxConcurrentConsumers(concurrency);
168→        factory.setBatchListener(true);
169→        factory.setConsumerBatchEnabled(true);
170→        factory.setBatchSize(batchMaxSize);
171→        factory.setPrefetchCount(batchMaxSize);
172→        factory.setReceiveTimeout(receiveTimeoutMs);
173→        factory.setAcknowledgeMode(AcknowledgeMode.AUTO);
174→        factory.setDefaultRequeueRejected(false);
175→        return factory;
176→    }
