492→    private static String doGet(String path) throws Exception {
493→        URL url = new URL(BASE_URL + path);
494→        HttpURLConnection conn = (HttpURLConnection) url.openConnection();
495→        conn.setRequestMethod("GET");
496→        conn.setRequestProperty("Cookie", COOKIE);
497→        return readResponse(conn);
498→    }
499→
500→    private static String doPost(String path, String json) throws Exception {
501→        URL url = new URL(BASE_URL + path);
502→        HttpURLConnection conn = (HttpURLConnection) url.openConnection();
503→        conn.setRequestMethod("POST");
504→        conn.setRequestProperty("Content-Type", "application/json");
505→        conn.setRequestProperty("Cookie", COOKIE);
506→        conn.setDoOutput(true);
507→        try (OutputStream os = conn.getOutputStream()) {
508→            os.write(json.getBytes("UTF-8"));
509→        }
510→        return readResponse(conn);
511→    }
512→
513→    private static String readResponse(HttpURLConnection conn) throws Exception {
514→        int code = conn.getResponseCode();
515→        InputStream is = code >= 400 ? conn.getErrorStream() : conn.getInputStream();
516→        if (is == null) return "{\"success\":false,\"code\":" + code + "}";
517→        BufferedReader br = new BufferedReader(new InputStreamReader(is, "UTF-8"));
518→        StringBuilder sb = new StringBuilder();
519→        String line;
520→        while ((line = br.readLine()) != null) {
521→            sb.append(line);
522→        }
523→        br.close();
524→        return sb.toString();
525→    }
526→
527→    private static String extractId(String json) {
528→        int start = json.indexOf("\"id\":\"");
529→        if (start == -1) return null;
530→        start += 6;
531→        int end = json.indexOf("\"", start);
532→        return end == -1 ? null : json.substring(start, end);
533→    }
534→
535→    private static String extractIdByName(String json, String name) {
536→        int namePos = json.indexOf("\"appName\":\"" + name + "\"");
537→        if (namePos == -1) return null;
538→        int idStart = json.lastIndexOf("\"id\":\"", namePos);
539→        if (idStart == -1) return null;
540→        idStart += 6;
541→        int idEnd = json.indexOf("\"", idStart);
542→        return idEnd == -1 ? null : json.substring(idStart, idEnd);
543→    }
