547→    private static void assertSuccess(String result, String message) {
548→        if (result.contains("\"success\":true") && result.contains("\"code\":200")) {
549→            System.out.println("  [PASS] " + message);
550→            passed++;
551→        } else {
552→            System.out.println("  [FAIL] " + message);
553→            System.out.println("         Response: " + truncate(result, 200));
554→            failed++;
555→        }
556→    }
