558→    private static void assertNotSuccess(String result, String message) {
559→        if (!result.contains("\"success\":true") || !result.contains("\"code\":200")) {
560→            System.out.println("  [PASS] " + message);
561→            passed++;
562→        } else {
563→            System.out.println("  [FAIL] " + message + " (expected failure but got success)");
564→            failed++;
565→        }
566→    }
